// 🔥 2026 TRENDING ANIMATIONS - 5 NEW STYLES
const MorphingBlobBackground = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current!
    const ctx = canvas.getContext('2d')!
    let time = 0

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    const animate = () => {
      ctx.fillStyle = 'rgba(15, 10, 35, 0.15)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      time += 0.015
      const centerX = canvas.width / 2
      const centerY = canvas.height / 2

      // Multiple morphing blobs
      for(let i = 0; i < 3; i++) {
        ctx.save()
        ctx.translate(centerX + Math.sin(time + i) * 100, centerY + Math.cos(time * 0.7 + i) * 80)
        
        ctx.shadowColor = `hsl(${210 + i * 30}, 70%, 55%)`
        ctx.shadowBlur = 40
        
        ctx.beginPath()
        for(let j = 0; j < 12; j++) {
          const angle = (j / 12) * Math.PI * 2 + time * (0.5 + i * 0.2)
          const radius = 80 + Math.sin(angle * 3 + time * 2) * 30 + i * 20
          const x = Math.cos(angle) * radius
          const y = Math.sin(angle) * radius
          if (j === 0) ctx.moveTo(x, y)
          else ctx.lineTo(x, y)
        }
        ctx.closePath()
        
        const gradient = ctx.createRadialGradient(0, 0, 0, 0, 0, 150)
        gradient.addColorStop(0, `hsla(${210 + i * 30}, 70%, 55%, 0.7)`)
        gradient.addColorStop(0.7, `hsla(${210 + i * 30}, 70%, 45%, 0.3)`)
        gradient.addColorStop(1, 'transparent')
        ctx.fillStyle = gradient
        ctx.fill()
        ctx.restore()
      }

      requestAnimationFrame(animate)
    }
    animate()

    return () => window.removeEventListener('resize', resize)
  }, [])

  return <canvas ref={canvasRef} className="fixed inset-0 z-0 pointer-events-none" />
}

const KineticTypographyBackground = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current!
    const ctx = canvas.getContext('2d')!
    let time = 0
    const words = ['CODE', 'DESIGN', 'INNOVATE', 'CREATE', 'BUILD']

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    const animate = () => {
      ctx.fillStyle = 'rgba(20, 15, 40, 0.1)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      time += 0.02
      const fontSize = 120 + Math.sin(time) * 20

      words.forEach((word, i) => {
        const x = (canvas.width / words.length) * i + canvas.width / words.length / 2
        const y = canvas.height / 2 + Math.sin(time * 1.5 + i) * 100
        
        ctx.save()
        ctx.translate(x, y)
        ctx.rotate(Math.sin(time * 2 + i) * 0.3)
        ctx.shadowColor = `hsl(${280 + i * 20}, 70%, 60%)`
        ctx.shadowBlur = 30
        
        ctx.font = `bold ${fontSize}px -apple-system, sans-serif`
        ctx.fillStyle = `hsla(${280 + i * 20}, 70%, 60%, ${0.8 + Math.sin(time * 3 + i) * 0.2})`
        ctx.textAlign = 'center'
        ctx.textBaseline = 'middle'
        ctx.fillText(word, 0, 0)
        ctx.restore()
      })

      requestAnimationFrame(animate)
    }
    animate()

    return () => window.removeEventListener('resize', resize)
  }, [])

  return <canvas ref={canvasRef} className="fixed inset-0 z-0 pointer-events-none" />
}

const BentoGridBackground = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current!
    const ctx = canvas.getContext('2d')!
    let time = 0

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    const animate = () => {
      ctx.fillStyle = 'rgba(12, 15, 35, 0.12)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      time += 0.01
      const cellSize = 80

      for(let x = 0; x < canvas.width; x += cellSize) {
        for(let y = 0; y < canvas.height; y += cellSize) {
          const pulse = Math.sin(time * 2 + x * 0.01 + y * 0.01) * 0.5 + 0.5
          const hue = 200 + pulse * 60
          
          ctx.strokeStyle = `hsla(${hue}, 70%, 55%, ${0.3 + pulse * 0.3})`
          ctx.lineWidth = 2 + pulse * 2
          ctx.strokeRect(x, y, cellSize, cellSize)
          
          // Inner glow
          ctx.shadowColor = `hsla(${hue}, 70%, 55%, 0.8)`
          ctx.shadowBlur = 15
          ctx.fillStyle = `hsla(${hue}, 70%, 55%, ${pulse * 0.2})`
          ctx.fillRect(x + 4, y + 4, cellSize - 8, cellSize - 8)
          ctx.shadowBlur = 0
        }
      }

      requestAnimationFrame(animate)
    }
    animate()

    return () => window.removeEventListener('resize', resize)
  }, [])

  return <canvas ref={canvasRef} className="fixed inset-0 z-0 pointer-events-none" />
}

const FloatingCodeMatrix = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current!
    const ctx = canvas.getContext('2d')!
    const streams: Array<{x: number, y: number, speed: number, chars: string[]}> = []

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    // Initialize streams
    for(let i = 0; i < 50; i++) {
      streams.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        speed: 0.5 + Math.random() * 2,
        chars: '01<>[](){}+-*/=ReactNextjsNodeTypeScript'.split('')
      })
    }

    const animate = () => {
      ctx.fillStyle = 'rgba(6, 12, 35, 0.1)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      streams.forEach(stream => {
        ctx.shadowColor = '#00ff88'
        ctx.shadowBlur = 20
        
        for(let i = 0; i < 15; i++) {
          const char = stream.chars[Math.floor(Math.random() * stream.chars.length)]
          const fontSize = 14 + i * 2
          const alpha = 1 - i * 0.06
          
          ctx.font = `bold ${fontSize}px monospace`
          ctx.fillStyle = `rgba(0, 255, 136, ${alpha})`
          ctx.textAlign = 'center'
          ctx.fillText(char, stream.x, stream.y + i * 25)
        }
        
        stream.y += stream.speed
        if (stream.y > canvas.height + 100) {
          stream.y = -100
          stream.x = Math.random() * canvas.width
        }
      })
      
      ctx.shadowBlur = 0
      requestAnimationFrame(animate)
    }
    animate()

    return () => window.removeEventListener('resize', resize)
  }, [])

  return <canvas ref={canvasRef} className="fixed inset-0 z-0 pointer-events-none" />
}

const WaveformVisualizer = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  
  useEffect(() => {
    const canvas = canvasRef.current!
    const ctx = canvas.getContext('2d')!
    let time = 0
    let mouseX = canvas.width / 2

    const resize = () => {
      canvas.width = window.innerWidth
      canvas.height = window.innerHeight
    }
    resize()
    window.addEventListener('resize', resize)

    const handleMouseMove = (e: MouseEvent) => {
      mouseX = e.clientX
    }
    window.addEventListener('mousemove', handleMouseMove)

    const animate = () => {
      ctx.fillStyle = 'rgba(8, 15, 40, 0.15)'
      ctx.fillRect(0, 0, canvas.width, canvas.height)

      time += 0.02
      const centerY = canvas.height / 2
      const slices = 200

      ctx.shadowColor = '#6366f1'
      ctx.shadowBlur = 25

      for(let i = 0; i < slices; i++) {
        const x = (i / slices) * canvas.width
        const wave1 = Math.sin((x * 0.01 + time) * 3) * 80
        const wave2 = Math.sin((x * 0.015 + time * 1.3) * 2) * 60
        const wave3 = Math.cos((x * 0.008 + time * 0.7) * 4) * 40
        const y = centerY + wave1 + wave2 + wave3
        
        const hue = 220 + (mouseX / canvas.width) * 60
        const gradient = ctx.createLinearGradient(x, y - 100, x, y + 100)
        gradient.addColorStop(0, `hsla(${hue}, 70%, 55%, 0.9)`)
        gradient.addColorStop(1, `hsla(${hue}, 70%, 35%, 0.2)`)
        
        ctx.fillStyle = gradient
        ctx.fillRect(x, y - 100, 4, 200)
      }

      ctx.shadowBlur = 0
      requestAnimationFrame(animate)
    }
    animate()

    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('resize', resize)
    }
  }, [])

  return <canvas ref={canvasRef} className="fixed inset-0 z-0 pointer-events-none" />
}

